#include <stdio.h>
#include <string.h>

int levenshteinDistance(char* str1, char* str2) 
{ 
    int m = strlen(str1); 
    int n = strlen(str2); 

    // Create a matrix to store results of subproblems 
    int dp[m+1][n+1]; 

    // Initialize first row and column 
    for (int i=0; i<=m; i++) 
        dp[i][0] = i; 

    for (int j=0; j<=n; j++) 
        dp[0][j] = j; 

    // Fill in the matrix 
    for (int i=1; i<=m; i++) 
        for (int j=1; j<=n; j++) 
            if (str1[i-1] == str2[j-1]) 
                dp[i][j] = dp[i-1][j-1]; 
            else
                dp[i][j] = 1 + min(dp[i][j-1], dp[i-1][j], dp[i-1][j-1]); 

    return dp[m][n]; 
} 

// Driver code 
int main() 
{ 
    char str1[] = "Python"; 
    char str2[] = "Perl"; 

    printf("The Levenshtein Distance is %d", levenshteinDistance(str1, str2)); 

    return 0; 
}
