    """
    Partitions the given list into two parts such that
    the sum of the two parts are equal.
    @param nums: List
    @return: List
    """
    total = sum(nums)
    curr_sum = 0
    left_list = []
    right_list = []

    for num in nums:
        if curr_sum <= total/2:
            left_list.append(num)
            curr_sum += num
        else:
            right_list.append(num)
